#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <stdexcept>

std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a buffer to hold the data
    std::vector<uint8_t> buffer;

    // Create buffer_write_adaptor object for the buffer
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> writer(buffer);

    // Check available space before writing
    if (writer.free() < input_data.size()) {
        throw std::runtime_error("Insufficient buffer space");
    }

    // Write the input data to the buffer
    writer.write(input_data.data(), input_data.size());

    // Create buffer_read_adaptor object for the same buffer
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> reader(buffer);

    // Check the size of the data available to read
    if (reader.size() < input_data.size()) {
        throw std::runtime_error("Insufficient data in buffer");
    }

    // Read the data back from the buffer
    std::vector<uint8_t> output_data(input_data.size());
    reader.read(output_data.data(), input_data.size());

    return output_data;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // Create buffer_read_adaptor object for the buffer
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> reader(buffer_data);

    // Check if there's enough data to peek
    if (reader.size() < peek_size) {
        throw std::runtime_error("Insufficient data to peek");
    }

    // Use read_ptr() to get pointer to current read position
    const uint8_t* read_ptr = reader.read_ptr();

    // Use copy() to peek at data without moving the read cursor
    std::vector<uint8_t> peeked_data(peek_size);
    reader.copy(peeked_data.data(), peek_size);

    // Use read() to actually consume the data (advance read pointer)
    reader.read(peeked_data.data(), peek_size);

    return peeked_data;
}
