    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor<const std::span<const uint8_t>> buffer_adaptor(buffer);
    hexi::binary_stream stream(buffer_adaptor);

    // Extract sensor name using view (null-terminated string)
    auto name_view = stream.view();

    // Check bounds before reading sensor_id
    stream.enforce_read_bounds(sizeof(uint32_t));

    uint32_t sensor_id;
    stream.get(&sensor_id, 1);

    // Skip remaining data
    size_t remaining = buffer.size() - sizeof(uint32_t);
